using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class ChallengeConfiguration : IEntityTypeConfiguration<Challenge>{public void Configure(EntityTypeBuilder<Challenge> builder){builder.ToTable("challenges");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("challenge_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Title).HasMaxLength(150).IsRequired();builder.Property(e => e.GoalType).HasConversion<string>().HasMaxLength(30);builder.HasOne(e => e.Group).WithMany().HasForeignKey(e => e.GroupId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.CreatedByUser).WithMany().HasForeignKey(e => e.CreatedByUserId);builder.HasIndex(e => new { e.GroupId, e.IsActive });}}
